const data = $input.first().json.data;

// Extract all items
const itemMatches = [...data.matchAll(/<item>([\s\S]+?)<\/item>/g)];

const articles = itemMatches.map(item => {
  const content = item[1];

  const titleMatch = content.match(/<title><!\[CDATA\[(.+?)\]\]><\/title>/);
  const linkMatch = content.match(/<link>(https:\/\/venturebeat\.com\/.+?)<\/link>/);
  const descMatch = content.match(/<description><!\[CDATA\[([\s\S]+?)\]\]><\/description>/);
  const dateMatch = content.match(/<pubDate>(.+?)<\/pubDate>/);

  return {
    json: {
      title: titleMatch ? titleMatch[1] : "",
      link: linkMatch ? linkMatch[1] : "",
      description: descMatch ? descMatch[1].replace(/<[^>]+>/g, '').substring(0, 500) : "",
      pubDate: dateMatch ? dateMatch[1] : "",
    }
  };
});

return articles;

const aiItems = $input.all();
const originalItems = $('Code in JavaScript').all();

// Pick the first item as the best article
const bestAiItem = aiItems[0].json.output?.[0]?.content?.[0]?.text || "";
const bestOriginal = originalItems[0].json;

const titleMatch = bestAiItem.match(/SelectedTitle:\s*(.+)/);
const linkMatch = bestAiItem.match(/SelectedLink:\s*(.+)/);
const descMatch = bestAiItem.match(/SelectedDescription:\s*([\s\S]+?)(?=Reason:)/);
const reasonMatch = bestAiItem.match(/Reason:\s*(.+)/);
const keywordsMatch = bestAiItem.match(/Keywords:\s*(.+)/);

return [{
  json: {
    title: titleMatch ? titleMatch[1].trim() : bestOriginal.title,
    link: bestOriginal.link,
    description: descMatch ? descMatch[1].trim() : bestOriginal.description,
    reason: reasonMatch ? reasonMatch[1].trim() : "",
    keywords: keywordsMatch ? keywordsMatch[1].trim() : "",
    pubDate: bestOriginal.pubDate,
  }
}];

const aiOutput = $input.first().json.output?.[0]?.content?.[0]?.text || "";
const original = $('Code in JavaScript1').first().json;

const headlineMatch = aiOutput.match(/###?\s*Headline:\s*(.+)/);
const blogPostMatch = aiOutput.match(/BlogPost:\s*([\s\S]+)/);

return [{
  json: {
    title: original.title,
    link: original.link,
    keywords: original.keywords,
    pubDate: original.pubDate,
    headline: headlineMatch ? headlineMatch[1].trim() : original.title,
    blogPost: blogPostMatch ? blogPostMatch[1].trim() : "",
    date: new Date().toDateString(),
  }
}];

const aiOutput = $input.first().json.output?.[0]?.content?.[0]?.text || "";
const original = $('Code in JavaScript2').first().json;

const linkedinMatch = aiOutput.match(/LinkedIn:\s*([\s\S]+?)(?=Twitter:)/);
const twitterMatch = aiOutput.match(/Twitter:\s*([\s\S]+?)(?=Instagram:)/);
const instagramMatch = aiOutput.match(/Instagram:\s*([\s\S]+)/);

return [{
