    instagram: instagramMatch ? instagramMatch[1].trim() : "",
    socialPosts: `LinkedIn: ${linkedinMatch ? linkedinMatch[1].trim() : ""}\n\nTwitter: ${twitterMatch ? twitterMatch[1].trim() : ""}\n\nInstagram: ${instagramMatch ? instagramMatch[1].trim() : ""}`,
  }
}];
